SELECT COUNT(*) AS QUANTIDADE FROM LATTES_P_PRODBIB LP JOIN LATTES_PRODBIB PB ON PB.PK = LP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LP.FK_SIAPE WHERE LOWER(S.SIGLA_CAMPUS) = LOWER('lin') AND LOWER(S.GENERO) = LOWER('masculino') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%biologia geral%' AND TRIM(PB.ANO) = '2024' AND LOWER(COALESCE(PB.TIPO, '')) LIKE '%capitulo de livro%'